// Get the input data from the Error Trigger (assuming one item)
const inputItem = $input.first().json;

// Initialize variables based on error type
let executionData, errorData, workflowData, nodeName, nodeType, errorMessage, errorStack, inputData, executionId, workflowId, workflowName;

if (inputItem.execution) {
  // Standard error case
  executionData = inputItem.execution;
  workflowData = inputItem.workflow;
  errorData = executionData.error;

  executionId = executionData.id || 'Unknown';
  workflowId = workflowData.id || 'Unknown';
  workflowName = workflowData.name || 'AI Social Media Agent';

  nodeName = executionData.lastNodeExecuted || 'Unknown Node';
  nodeType = 'Unknown Type'; // Not available in standard case; adjust if needed

  errorMessage = errorData.message || 'No error message available';
  errorStack = errorData.stack || 'No stack trace available';
  inputData = JSON.stringify({}); // Input data not provided by Error Trigger; stub or remove if unnecessary
} else if (inputItem.trigger) {
  // Error in trigger node case
  executionData = inputItem.trigger;
  workflowData = inputItem.workflow;
  errorData = executionData.error;

  executionId = 'Unknown'; // Not available in trigger error case
  workflowId = workflowData.id || 'Unknown';
  workflowName = workflowData.name || 'AI Social Media Agent';

  nodeName = errorData.node?.name || 'Unknown Node';
  nodeType = errorData.node?.type || 'Unknown Type';

  errorMessage = errorData.message || 'No error message available';
  errorStack = errorData.cause?.stack || errorData.stack || 'No stack trace available';
  inputData = JSON.stringify(errorData.node?.parameters || {}); // Approximate input data from node params; adjust as needed
} else {
  // Fallback for unexpected input: Log and set defaults
  console.log('Unexpected input data structure from Error Trigger:', JSON.stringify(inputItem, null, 2));

  // Set fallback values to allow workflow to continue
  executionData = {};
  workflowData = {};
  errorData = {};

  executionId = 'Unknown';
  workflowId = 'Unknown';
  workflowName = 'AI Social Media Agent (Fallback)';
  nodeName = 'Unknown Node';
  nodeType = 'Unknown Type';
  errorMessage = 'Unexpected error data structure from Error Trigger';
  errorStack = 'No stack trace available (fallback)';
  inputData = JSON.stringify(inputItem || {}); // Use raw input as fallback for inputData
}

// Define severity function (add your logic here)
function determineSeverity(errData) {
  // Example: Customize based on error type
  if (errData.message?.includes('critical')) return 'High';
  return 'Medium';
}

const errorInfo = {
  workflowName,
  executionId,
  timestamp: new Date().toISOString(),
  nodeName,
  nodeType,
  errorMessage,
  errorStack,
  inputData,
  workflowId,
  severity: determineSeverity(errorData)
};

// Define email fields (customize as needed)
const emailSubject = `Error in Workflow: ${errorInfo.workflowName}`;
const emailBody = `
Timestamp: ${errorInfo.timestamp}
Node: ${errorInfo.nodeName} (${errorInfo.nodeType})
Error: ${errorInfo.errorMessage}
Stack: ${errorInfo.errorStack}
Input Data: ${errorInfo.inputData}
Severity: ${errorInfo.severity}
`;

// Output for downstream nodes (email and Google Sheets)
return [
  {
    json: {
      emailSubject,
      emailBody,
      errorInfo  // Pass for Google Sheets logging
    }
  }
];
